const fs = require('fs');
const path = require('path');

const COUNT = 20;
const DEFAULT_EMAIL = 'sales@yourdomain.com';
const DEFAULT_MAX_DEVICES = 2;
const DEFAULT_EXPIRES_AT = 'NULL';

const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
const seg = (n) => Array.from({ length: n }, () => chars[Math.floor(Math.random() * chars.length)]).join('');
const makeKey = () => `INKF-${seg(4)}-${seg(4)}-${seg(4)}`;

const keys = new Set();
while (keys.size < COUNT) keys.add(makeKey());

const keyList = Array.from(keys);
const lines = [
  '-- Generated by scripts/generate-licenses.js',
  '-- Review email/max_devices/expires_at values before running in Supabase',
  'INSERT INTO license_keys (key, email, max_devices, expires_at) VALUES',
];

keyList.forEach((k, i) => {
  const suffix = i === keyList.length - 1 ? ';' : ',';
  lines.push(`('${k}', '${DEFAULT_EMAIL}', ${DEFAULT_MAX_DEVICES}, ${DEFAULT_EXPIRES_AT})${suffix}`);
});

const sqlOut = path.join(process.cwd(), 'generated-license-20.sql');
const txtOut = path.join(process.cwd(), 'generated-license-20.txt');

fs.writeFileSync(sqlOut, `${lines.join('\n')}\n`, 'utf8');
fs.writeFileSync(txtOut, `${keyList.join('\n')}\n`, 'utf8');

console.log('Done: generated-license-20.sql তৈরি হয়েছে');
console.log('Done: generated-license-20.txt তৈরি হয়েছে');
console.log('Preview first 5 keys:');
keyList.slice(0, 5).forEach((k) => console.log(`- ${k}`));
